As an AI text model, I cannot directly generate or render a 3D image file (like a .obj, .fbx, or a screenshot). However, I can provide you with the **complete code** to render a 3D house using **Three.js**, a popular JavaScript library for 3D graphics in the browser.

You can copy the code below, save it as an `.html` file, and open it in any modern web browser to see the rendered house.

### 3D House Renderer (Three.js)

This code creates a simple house with a roof, walls, a door, and a window, complete with lighting and shadows.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Render (Click & Drag to Rotate)</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x800000 }); // Dark Red
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x333333 }); // Dark Grey
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.6 }); // Light Blue

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, wallMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallHeight = 4;
        const wallGeo = new THREE.BoxGeometry(10, wallHeight, 1);
        const wall1 = new THREE.Mesh(wallGeo, wallMaterial);
        wall1.position.set(0, wallHeight / 2, 4);
        wall1.castShadow = true;
        wall1.receiveShadow = true;
        houseGroup.add(wall1);

        const wall2 = new THREE.Mesh(wallGeo, wallMaterial);
        wall2.position.set(0, wallHeight / 2, -4);
        wall2.castShadow = true;
        wall2.receiveShadow = true;
        houseGroup.add(wall2);

        const wall3 = new THREE.Mesh(wallGeo, wallMaterial);
        wall3.position.set(4, wallHeight / 2, 0);
        wall3.castShadow = true;
        wall3.receiveShadow = true;
        houseGroup.add(wall3);

        const wall4 = new THREE.Mesh(wallGeo, wallMaterial);
        wall4.position.set(-4, wallHeight / 2, 0);
        wall4.castShadow = true;
        wall4.receiveShadow = true;
        houseGroup.add(wall4);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1.5, 4.1);
        door.castShadow = true;
        houseGroup.add(door);

        // Window
        const winGeo = new THREE.BoxGeometry(1.5, 1.5, 0.2);
        const windowMesh = new THREE.Mesh(winGeo, windowMaterial);
        windowMesh.position.set(0, 3, 4.1);
        windowMesh.castShadow = true;
        houseGroup.add(windowMesh);

        // Roof
        const roofGeo = new THREE.ConeGeometry(9, 3, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = wallHeight + 1.5;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        roof.receiveShadow = true;
        houseGroup.add(roof);

        scene.add(houseGroup);

        // 6. Ground (Grass)
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const groundMat = new THREE.MeshStandardMaterial({ color: 0x228B22 });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.position.y = -0.51;
        ground.receiveShadow = true;
        scene.add(ground);

        // 7. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Create a file:** Create a new file on your computer named `house.html`.
2.  **Paste:** Paste the code above into that file and save it.
3.  **Run:** Double-click `house.html` to open it in Chrome, Firefox, Safari, or Edge.

### What this code does:
*   **Scene Setup:** Initializes a 3D scene, camera, and renderer.
*   **Lighting:** Adds ambient light (soft fill) and a directional light (sun) that casts shadows.
*   **Geometry:** Constructs the house using basic shapes:
    *   `BoxGeometry` for walls, floor, and door.
    *   `ConeGeometry` for the roof.
    *   `PlaneGeometry` for the grass.
*   **Interactivity:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house, or scroll to zoom in/out.
